sql:
SELECT DISTINCT c.first_name, c.last_name
FROM customers c
JOIN reviews r ON c.customer_id = r.customer_id;

SELECT AVG(ring_diameter_mm) AS Average_Ring_Diameter
FROM ring_sizes
WHERE eu_size = (SELECT MAX(eu_size) FROM ring_sizes);

SELECT DISTINCT c.first_name, c.last_name
FROM customers c
JOIN orders o ON c.customer_id = o.customer_id;

SELECT guide_name, guide_description
FROM sizes_guides
WHERE created_date > '2023-01-01';

external_knowledge:
- 'flagship' refers to the main or primary order (order_id = 1).;
- 'timeline' represents the order's placement date (order_date).;
- 'treasure chest' symbolizes the total amount of the order (total_amount).;
- 'treasures (products)' are the items within the order (product_name and price).;

sql:
SELECT DISTINCT p.product_name
FROM products p
JOIN promotions prom ON p.product_id = prom.product_id;

external_knowledge:
- 'items' refers to products.; 
- 'special offer' indicates a discount percentage greater than zero.; 
- 'last month of the second quarter of this year' refers to June 2023.

sql:
SELECT p.product_id, p.product_name
FROM products p
WHERE p.product_id IN (SELECT product_id FROM promotions);
